const root = document.getElementById('w-profinite');
const svg = root.querySelector('svg');
const text = root.querySelector('#pf-text');
const btns = root.querySelectorAll('button[data-pf]');
let mode = 'all';

const layouts = {
  all: {
    text: "$G_\\mathbb{Q}$ surjects onto every finite Galois group $\\Gal(K/\\mathbb{Q})$. Reading the diagram downward is a tower of quotients; reading upward is the inverse limit.",
    nodes: [
      {id:'G', x:410, y:40, label:'G_Q', big:true},
      {id:'A', x:180, y:140, label:'Gal(Q(ζ₃)/Q)'},
      {id:'B', x:410, y:140, label:'Gal(Q(√2)/Q)'},
      {id:'C', x:640, y:140, label:'Gal(splitting x³−2)/Q)'},
      {id:'D', x:260, y:240, label:'Z/2'},
      {id:'E', x:410, y:240, label:'Z/2'},
      {id:'F', x:560, y:240, label:'S₃'},
      {id:'tr', x:410, y:300, label:'{1}'}
    ],
    edges: [['G','A'],['G','B'],['G','C'],['A','D'],['B','E'],['C','F'],['D','tr'],['E','tr'],['F','tr']]
  },
  abelian: {
    text: "The maximal abelian quotient $G_\\mathbb{Q}^{ab}$ is $\\widehat{\\mathbb{Z}}^\\times$, via the cyclotomic tower (Kronecker–Weber). Every 1-d Galois representation factors through this quotient.",
    nodes: [
      {id:'G', x:410, y:40, label:'G_Q', big:true},
      {id:'Gab', x:410, y:140, label:'G_Q^ab ≅ Ẑ^×'},
      {id:'A1', x:220, y:240, label:'(Z/5)^×'},
      {id:'A2', x:400, y:240, label:'(Z/7)^×'},
      {id:'A3', x:580, y:240, label:'(Z/11)^×'}
    ],
    edges: [['G','Gab'],['Gab','A1'],['Gab','A2'],['Gab','A3']]
  },
  cyclo: {
    text: "The cyclotomic tower $\\mathbb{Q}(\\mu_{\\ell^n})$ has $\\Gal = (\\mathbb{Z}/\\ell^n)^\\times$. Taking the limit gives the cyclotomic character $G_\\mathbb{Q} \\to \\mathbb{Z}_\\ell^\\times$.",
    nodes: [
      {id:'G', x:410, y:40, label:'G_Q', big:true},
      {id:'Z', x:410, y:140, label:'Z_ℓ^×'},
      {id:'n3', x:410, y:210, label:'(Z/ℓ³)^×'},
      {id:'n2', x:410, y:260, label:'(Z/ℓ²)^×'},
      {id:'n1', x:410, y:310, label:'(Z/ℓ)^×'}
    ],
    edges: [['G','Z'],['Z','n3'],['n3','n2'],['n2','n1']]
  }
};

function render(){
  svg.innerHTML = '';
  const L = layouts[mode];
  text.textContent = L.text;
  for(const [from, to] of L.edges){
    const a = L.nodes.find(n=>n.id===from), b = L.nodes.find(n=>n.id===to);
    drawArrow(svg, [a.x, a.y+18], [b.x, b.y-18], {markerId:'pf-arr', color:'var(--line)', pad1:2, pad2:2});
  }
  for(const n of L.nodes){
    const r = n.big ? 26 : 18;
    const w = Math.max(n.label.length*7+18, r*2+4);
    svg.appendChild(SVG('rect', {x:n.x-w/2, y:n.y-r*0.7, width:w, height:r*1.4, rx:6,
      fill: n.big ? 'var(--panel2)' : 'var(--panel)',
      stroke: n.big ? 'var(--yellow)' : 'var(--blue)', 'stroke-width':1.5}));
    const t = SVG('text', {x:n.x, y:n.y+4, 'text-anchor':'middle', 'font-size':n.big?15:12,
      fill: n.big?'var(--yellow)':'#fff', 'font-weight':600});
    t.textContent = n.label;
    svg.appendChild(t);
  }
}

btns.forEach(b => b.addEventListener('click', () => {
  btns.forEach(x => x.classList.remove('active'));
  b.classList.add('active');
  mode = b.dataset.pf;
  render();
}));
render();

const root = document.getElementById('w-diagram');
const svg = root.querySelector('svg');
const text = root.querySelector('#rep-text');
const btns = root.querySelectorAll('button[data-field]');
let field = 'Ql';

const info = {
  C:  {target:'GL_n(C)', label:'Artin', color:'var(--violet)',
       note:"Classical (complex) representation. Factors through a finite quotient. Image is finite. Conjectural Artin L-functions."},
  Ql: {target:'GL_n(Q̄_ℓ)', label:'ℓ-adic', color:'var(--yellow)',
       note:"The workhorse. Comes from ℓ-adic étale cohomology of algebraic varieties. Image need NOT be finite. Used for elliptic curves, modular forms."},
  Fl: {target:'GL_n(F̄_ℓ)', label:'mod ℓ', color:'var(--pink)',
       note:"Reduction of an ℓ-adic representation mod ℓ. Image always finite. Serre's conjecture: every odd, irreducible, 2-d mod-ℓ representation is modular."}
};

function render(){
  svg.innerHTML = '';
  // G_Q box
  svg.appendChild(SVG('rect', {x:60, y:90, width:160, height:60, rx:8,
    fill:'var(--panel2)', stroke:'var(--blue)', 'stroke-width':1.6}));
  const t1 = SVG('text', {x:140, y:115, 'text-anchor':'middle', 'font-size':18, fill:'#fff', 'font-weight':600});
  t1.textContent = 'G_Q';
  svg.appendChild(t1);
  const t1s = SVG('text', {x:140, y:138, 'text-anchor':'middle', 'font-size':11, fill:'var(--mute)'});
  t1s.textContent = 'absolute Galois group';
  svg.appendChild(t1s);

  const I = info[field];
  // target box
  svg.appendChild(SVG('rect', {x:460, y:90, width:220, height:60, rx:8,
    fill:'var(--panel2)', stroke:I.color, 'stroke-width':1.6}));
  const t2 = SVG('text', {x:570, y:115, 'text-anchor':'middle', 'font-size':18, fill:'#fff', 'font-weight':600});
  t2.textContent = I.target;
  svg.appendChild(t2);
  const t2s = SVG('text', {x:570, y:138, 'text-anchor':'middle', 'font-size':11, fill:'var(--mute)'});
  t2s.textContent = I.label + ' representation';
  svg.appendChild(t2s);

  drawArrow(svg, [220, 120], [460, 120], {markerId:'rep-'+field, color:I.color, label:'ρ', width:2, pad1:4, pad2:4});
  text.textContent = I.note;
}

btns.forEach(b => b.addEventListener('click', () => {
  btns.forEach(x => x.classList.remove('active'));
  b.classList.add('active');
  field = b.dataset.field;
  render();
}));
render();

const root = document.getElementById('w-cyclo');
const svg = root.querySelector('svg');
const elSel = root.querySelector('#cy-ell');
const nRng = root.querySelector('#cy-n');
const nLab = root.querySelector('#cy-nlab');
const aIn  = root.querySelector('#cy-a');
const aHint = root.querySelector('#cy-ahint');
const text = root.querySelector('#cy-text');

function gcd(a,b){ while(b){ [a,b]=[b,a%b]; } return a; }

function render(){
  svg.innerHTML = '';
  const ell = parseInt(elSel.value,10);
  const n = parseInt(nRng.value,10);
  nLab.textContent = 'n=' + n;
  const N = Math.pow(ell,n);
  let a = parseInt(aIn.value,10);
  if(!Number.isFinite(a)) a = 1;
  // nearest valid a (coprime to ell)
  if(a % ell === 0){ a = a+1; aIn.value = a; }
  const amod = mod(a, N);
  aHint.textContent = "σ acts by ζ ↦ ζ^" + a + " (must be coprime to " + ell + "; mod " + N + " → " + amod + ")";

  const cx = 360, cy = 150, R = 110;
  // outer title
  const tt = SVG('text',{x:cx, y:28, 'text-anchor':'middle', 'font-size':14, fill:'var(--yellow)'});
  tt.textContent = 'μ_'+N+' : '+N+' points';
  svg.appendChild(tt);

  // circle
  svg.appendChild(SVG('circle',{cx, cy, r:R, fill:'none', stroke:'var(--line)', 'stroke-width':1}));
  // points
  const pts = [];
  for(let k=0;k<N;k++){
    const th = 2*Math.PI*k/N - Math.PI/2;
    pts.push([cx + R*Math.cos(th), cy + R*Math.sin(th)]);
  }
  // action arrows k -> a*k (mod N), draw only 'primitive' images from a generator
  for(let k=1;k<N;k++){
    const j = mod(a*k, N);
    const [x1,y1] = pts[k], [x2,y2] = pts[j];
    if(k === j) continue;
    drawArrow(svg, [x1,y1], [x2,y2], {color:'var(--cyan)', markerId:'cy-arr', width:1, pad1:6, pad2:8, curve:10});
  }
  // points on top
  for(let k=0;k<N;k++){
    const prim = (gcd(k,N)===1);
    const r = prim ? 4.5 : 3;
    svg.appendChild(SVG('circle',{cx:pts[k][0], cy:pts[k][1], r,
      fill: prim ? 'var(--yellow)' : 'var(--mute)', stroke:'#0b0f16', 'stroke-width':1}));
  }
  // center label
  const c1 = SVG('text',{x:cx, y:cy-6, 'text-anchor':'middle', 'font-size':13, fill:'var(--mute)'});
  c1.textContent = 'ζ ↦ ζ^'+amod;
  svg.appendChild(c1);
  const c2 = SVG('text',{x:cx, y:cy+12, 'text-anchor':'middle', 'font-size':12, fill:'var(--mute)'});
  c2.textContent = '(Z/'+N+')^× has φ('+N+')='+phi(N)+' units';
  svg.appendChild(c2);

  const isUnit = (gcd(amod, N) === 1);
  text.textContent = isUnit
    ? "Valid χ(σ) = "+amod+" ∈ (Z/"+N+")^×. On the "+N+"-th roots of unity, σ permutes ζ^k to ζ^("+amod+"·k mod "+N+"). Yellow dots are primitive roots; gray dots are higher-order fixed loci."
    : "NOT a unit: "+amod+" shares a factor with "+N+", so this is not a Galois action on μ_"+N+".";
}

function phi(n){
  let r = n, m = n;
  for(let p=2;p*p<=m;p++){
    if(m%p===0){ while(m%p===0) m/=p; r -= r/p; }
  }
  if(m>1) r -= r/m;
  return Math.round(r);
}

elSel.addEventListener('change', render);
nRng.addEventListener('input', render);
aIn.addEventListener('input', render);
render();

const root = document.getElementById('w-tate');
const svg = root.querySelector('svg');
const elSel = root.querySelector('#tt-ell');
const btns = root.querySelectorAll('button[data-lvl]');
const text = root.querySelector('#tt-text');
let lvl = 2;

function render(){
  svg.innerHTML = '';
  const ell = parseInt(elSel.value,10);
  const N = Math.pow(ell, lvl);

  // three small lattices in a row
  const centers = [[170, 170], [400, 170], [630, 170]];
  const labels  = ['E[ℓ]', 'E[ℓ²]', 'E[ℓ³]'];
  const exps    = [1, 2, 3];
  const sizes   = [Math.pow(ell,1), Math.pow(ell,2), Math.pow(ell,3)];

  for(let i=0;i<3;i++){
    const [cx, cy] = centers[i];
    const Ni = sizes[i];
    const isActive = (exps[i] === lvl);
    // background
    svg.appendChild(SVG('rect',{x:cx-80, y:cy-80, width:160, height:160, rx:6,
      fill: isActive ? 'var(--panel2)' : 'var(--panel)',
      stroke: isActive ? 'var(--yellow)' : 'var(--line)', 'stroke-width':isActive?2:1}));
    // lattice of Ni × Ni
    const step = 140/(Ni);
    for(let a=0;a<Ni;a++) for(let b=0;b<Ni;b++){
      const x = cx - 70 + step*a + step/2;
      const y = cy - 70 + step*b + step/2;
      const r = isActive ? 2.5 : 1.8;
      svg.appendChild(SVG('circle',{cx:x, cy:y, r,
        fill: (a===0 && b===0) ? 'var(--green)' : (isActive ? 'var(--yellow)' : 'var(--mute)')}));
    }
    const t = SVG('text',{x:cx, y:cy+100, 'text-anchor':'middle', 'font-size':14,
      fill: isActive ? 'var(--yellow)' : 'var(--ink)', 'font-weight':600});
    t.textContent = labels[i] + ' (' + Ni + '×' + Ni + ')';
    svg.appendChild(t);
    const t2 = SVG('text',{x:cx, y:cy+118, 'text-anchor':'middle', 'font-size':11, fill:'var(--mute)'});
    t2.textContent = '≅ (Z/' + Ni + ')²';
    svg.appendChild(t2);
  }

  // [ell] arrows between them (right to left)
  drawArrow(svg, [centers[1][0] - 90, 170], [centers[0][0] + 90, 170],
    {color:'var(--cyan)', markerId:'tt-1', pad1:2, pad2:2, label:'[ℓ]', width:1.8});
  drawArrow(svg, [centers[2][0] - 90, 170], [centers[1][0] + 90, 170],
    {color:'var(--cyan)', markerId:'tt-2', pad1:2, pad2:2, label:'[ℓ]', width:1.8});

  // limit label
  const lim = SVG('text',{x:390, y:40, 'text-anchor':'middle', 'font-size':15, fill:'var(--violet)', 'font-weight':600});
  lim.textContent = 'T_ℓ E = lim← E[ℓⁿ] ≅ Z_ℓ²';
  svg.appendChild(lim);
  const lim2 = SVG('text',{x:390, y:60, 'text-anchor':'middle', 'font-size':12, fill:'var(--mute)'});
  lim2.textContent = 'ρ_{E,ℓ}: G_Q → GL₂(Z_ℓ)';
  svg.appendChild(lim2);
  const lim3 = SVG('text',{x:720, y:45, 'text-anchor':'middle', 'font-size':12, fill:'var(--mute)'});
  lim3.textContent = '···';
  svg.appendChild(lim3);

  text.textContent = "Level " + lvl + ": E[ℓ^" + lvl + "] ≅ (Z/" + N + ")² has " + (N*N)
    + " torsion points. Galois acts linearly, giving a continuous ρ: G_Q → GL₂(Z/" + N + "). Taking the inverse limit over all levels recovers ρ_{E,ℓ}.";
}

btns.forEach(b => b.addEventListener('click', () => {
  btns.forEach(x => x.classList.remove('active'));
  b.classList.add('active');
  lvl = parseInt(b.dataset.lvl,10);
  render();
}));
elSel.addEventListener('change', render);
render();

const root = document.getElementById('w-matrix');
const svg = root.querySelector('svg');
const pSel = root.querySelector('#mx-p');
const aR  = root.querySelector('#mx-a');
const aLab = root.querySelector('#mx-alab');
const text = root.querySelector('#mx-text');

function clampA(a, p){
  const m = Math.floor(2*Math.sqrt(p));
  return Math.max(-m, Math.min(m, a));
}

function updateRange(){
  const p = parseInt(pSel.value,10);
  const m = Math.floor(2*Math.sqrt(p));
  aR.min = -m; aR.max = m;
  aR.value = clampA(parseInt(aR.value,10), p);
}

function render(){
  svg.innerHTML = '';
  const p = parseInt(pSel.value,10);
  updateRange();
  const a = clampA(parseInt(aR.value,10), p);
  aLab.textContent = 'a='+a;

  // LEFT: matrix box
  const mx = 170, my = 170;
  svg.appendChild(SVG('rect',{x:mx-120, y:my-90, width:240, height:180, rx:8,
    fill:'var(--panel2)', stroke:'var(--yellow)', 'stroke-width':1.5}));
  const tt = SVG('text',{x:mx, y:my-60, 'text-anchor':'middle', 'font-size':13, fill:'var(--mute)'});
  tt.textContent = 'representative of ρ(Frob_p)';
  svg.appendChild(tt);
  // choose rational conjugacy-class representative with tr=a, det=p
  // use companion matrix [[0,-p],[1,a]] so tr = a, det = p
  const rows = [
    ['0', String(-p)],
    ['1', String(a)]
  ];
  for(let r=0;r<2;r++) for(let c=0;c<2;c++){
    const x = mx - 55 + c*70, y = my - 20 + r*42;
    svg.appendChild(SVG('rect',{x:x-24, y:y-16, width:48, height:32, rx:4, fill:'#0b0f16', stroke:'var(--line)'}));
    const t = SVG('text',{x, y:y+5, 'text-anchor':'middle', 'font-size':15, fill:'var(--ink)', 'font-family':'ui-monospace,monospace'});
    t.textContent = rows[r][c];
    svg.appendChild(t);
  }

  // brackets
  for(const xb of [mx-82, mx+82]){
    const dir = xb<mx ? 1 : -1;
    svg.appendChild(SVG('path',{d:`M${xb+dir*6} ${my-40} L${xb} ${my-40} L${xb} ${my+40} L${xb+dir*6} ${my+40}`,
      fill:'none', stroke:'var(--ink)', 'stroke-width':1.8}));
  }

  // RIGHT: characteristic polynomial + eigenvalues
  const rx = 550, ry = 80;
  const chrt = SVG('text',{x:rx, y:ry, 'text-anchor':'middle', 'font-size':16, fill:'var(--yellow)', 'font-weight':600});
  chrt.textContent = "char poly: t² − "+a+"t + "+p;
  svg.appendChild(chrt);

  // eigenvalues
  const disc = a*a - 4*p;
  let ev = '';
  let complex = false;
  if(disc >= 0){
    const s = Math.sqrt(disc);
    ev = 'α = ' + ((a+s)/2).toFixed(3) + ', β = ' + ((a-s)/2).toFixed(3);
  } else {
    const s = Math.sqrt(-disc);
    ev = 'α = ' + (a/2).toFixed(3) + ' + ' + (s/2).toFixed(3) + 'i,  β = conj';
    complex = true;
  }
  const ep = SVG('text',{x:rx, y:ry+26, 'text-anchor':'middle', 'font-size':13, fill:'var(--ink)', 'font-family':'ui-monospace,monospace'});
  ep.textContent = ev;
  svg.appendChild(ep);

  // circle of radius √p
  const cx = 570, cy = 230, R = 80;
  svg.appendChild(SVG('circle',{cx, cy, r:R, fill:'none', stroke:'var(--line)', 'stroke-width':1, 'stroke-dasharray':'4 4'}));
  svg.appendChild(SVG('line',{x1:cx-R-10, y1:cy, x2:cx+R+10, y2:cy, stroke:'var(--line)', 'stroke-width':0.5}));
  svg.appendChild(SVG('line',{x1:cx, y1:cy-R-10, x2:cx, y2:cy+R+10, stroke:'var(--line)', 'stroke-width':0.5}));
  const rlab = SVG('text',{x:cx+R+14, y:cy+4, 'text-anchor':'start', 'font-size':11, fill:'var(--mute)'});
  rlab.textContent = '|α|=√p='+Math.sqrt(p).toFixed(2);
  svg.appendChild(rlab);

  // plot eigenvalues
  const sp = Math.sqrt(p);
  let a1, a2;
  if(complex){
    const s = Math.sqrt(-disc)/2;
    a1 = {re: a/2, im: s};
    a2 = {re: a/2, im: -s};
  } else {
    const s = Math.sqrt(disc);
    a1 = {re: (a+s)/2, im:0};
    a2 = {re: (a-s)/2, im:0};
  }
  for(const pt of [a1,a2]){
    const sx = cx + R * pt.re / sp;
    const sy = cy - R * pt.im / sp;
    svg.appendChild(SVG('circle',{cx:sx, cy:sy, r:5, fill:'var(--yellow)', stroke:'#0b0f16', 'stroke-width':1.5}));
  }

  text.textContent = "Representative matrix with trace " + a + " and determinant " + p + ". Characteristic polynomial t² − " + a + "t + " + p + ". "
    + (complex ? "Complex-conjugate eigenvalues, both of modulus √p." : "Real eigenvalues (only possible when a² = 4p, i.e. on the boundary).")
    + "  |a| ≤ 2√p = " + (2*Math.sqrt(p)).toFixed(2) + ".";
}

pSel.addEventListener('change', render);
aR.addEventListener('input', render);
render();

const root = document.getElementById('w-apbar');
const svg = root.querySelector('svg');
const curSel = root.querySelector('#ap-curve');
const envCk = root.querySelector('#ap-env');
const text = root.querySelector('#ap-text');

// simple point-count for y^2 + a1 xy + a3 y = x^3 + a2 x^2 + a4 x + a6
function countPts(p, coeffs){
  const {a1=0, a2=0, a3=0, a4=0, a6=0} = coeffs;
  let n = 1; // point at infinity
  for(let x=0;x<p;x++){
    const rhs = mod(x*x*x + a2*x*x + a4*x + a6, p);
    // y^2 + (a1 x + a3) y = rhs  <=>  y^2 + By = rhs  where B = a1 x + a3
    const B = mod(a1*x + a3, p);
    for(let y=0;y<p;y++){
      if(mod(y*y + B*y - rhs, p) === 0) n++;
    }
  }
  return n;
}

// detect discriminant zero by a crude scan: if point count matches degenerate pattern, skip
const curves = {
  A: {label:'y² = x³ − x', coeffs:{a4:-1}, badPrimes:[2]},
  B: {label:'y² + y = x³ − x²', coeffs:{a2:-1, a3:1}, badPrimes:[11]},
  C: {label:'y² = x³ − 43x + 166', coeffs:{a4:-43, a6:166}, badPrimes:[2,13]}
};

function render(){
  svg.innerHTML = '';
  const cur = curves[curSel.value];
  const ps = primesUpTo(100);
  const W = 820, H = 300;
  const marL = 40, marR = 20, marT = 40, marB = 40;
  const plotW = W - marL - marR;
  const plotH = H - marT - marB;

  // compute a_p for each p
  const vals = [];
  let maxAbs = 0;
  for(const p of ps){
    if(cur.badPrimes.includes(p)){ vals.push({p, ap:null}); continue; }
    if(p>50){ vals.push({p, ap:null, skip:true}); continue; } // avoid slow point-count at large p in browser
    const np = countPts(p, cur.coeffs);
    const ap = p + 1 - np;
    vals.push({p, ap});
    if(Math.abs(ap) > maxAbs) maxAbs = Math.abs(ap);
  }
  // for p>50 use Hasse bound as placeholder
  for(const v of vals) if(v.skip) maxAbs = Math.max(maxAbs, 2*Math.sqrt(v.p));
  if(maxAbs < 4) maxAbs = 4;

  // axes
  const y0 = marT + plotH/2;
  svg.appendChild(SVG('line',{x1:marL, y1:y0, x2:W-marR, y2:y0, stroke:'var(--line)', 'stroke-width':1}));
  svg.appendChild(SVG('line',{x1:marL, y1:marT, x2:marL, y2:H-marB, stroke:'var(--line)', 'stroke-width':1}));

  // bars
  const n = ps.length;
  const bw = plotW / n * 0.8;
  for(let i=0;i<n;i++){
    const v = vals[i];
    const x = marL + plotW*(i+0.5)/n;
    if(v.ap === null && !v.skip){
      // bad prime
      svg.appendChild(SVG('rect',{x:x-bw/2, y:marT, width:bw, height:plotH, fill:'rgba(224,122,95,0.12)'}));
      continue;
    }
    if(v.skip) continue;
    const h = plotH/2 * (v.ap / maxAbs);
    svg.appendChild(SVG('rect',{x:x-bw/2, y: v.ap>=0 ? y0-h : y0, width:bw, height:Math.abs(h),
      fill: v.ap===0 ? 'var(--mute)' : (v.ap>0 ? 'var(--green)' : 'var(--pink)')}));
  }
  // selected prime labels
  const pickLabels = [2,7,17,31,47];
  for(let i=0;i<n;i++){
    if(!pickLabels.includes(ps[i])) continue;
    const x = marL + plotW*(i+0.5)/n;
    const t = SVG('text',{x, y:H-marB+14, 'text-anchor':'middle', 'font-size':10, fill:'var(--mute)'});
    t.textContent = ps[i];
    svg.appendChild(t);
  }

  // Hasse envelope
  if(envCk.checked){
    const path1 = [], path2 = [];
    for(let i=0;i<n;i++){
      const p = ps[i];
      const x = marL + plotW*(i+0.5)/n;
      const h = plotH/2 * (2*Math.sqrt(p) / maxAbs);
      path1.push([x, y0-h]);
      path2.push([x, y0+h]);
    }
    const d1 = 'M' + path1.map(p=>p.join(' ')).join(' L');
    const d2 = 'M' + path2.map(p=>p.join(' ')).join(' L');
    svg.appendChild(SVG('path',{d:d1, fill:'none', stroke:'var(--violet)', 'stroke-width':1.3, 'stroke-dasharray':'3 3'}));
    svg.appendChild(SVG('path',{d:d2, fill:'none', stroke:'var(--violet)', 'stroke-width':1.3, 'stroke-dasharray':'3 3'}));
  }

  // title
  const tt = SVG('text',{x:W/2, y:20, 'text-anchor':'middle', 'font-size':13, fill:'var(--yellow)'});
  tt.textContent = 'a_p for ' + cur.label + ' (red shade = bad reduction)';
  svg.appendChild(tt);

  // readout: list first few ap
  const first = vals.filter(v=>v.ap!==null && !v.skip).slice(0, 10)
    .map(v => 'a_'+v.p+'='+v.ap).join(', ');
  text.textContent = first + '.  Dashed violet lines are the Hasse envelope ±2√p.';
}

