const root = document.getElementById('w-hasse');
const svg = root.querySelector('svg');
const pSel = root.querySelector('#hs-p');
const aR = root.querySelector('#hs-a');
const aLab = root.querySelector('#hs-alab');
const text = root.querySelector('#hs-text');

function clampA(a,p){
  const m = Math.floor(2*Math.sqrt(p));
  return Math.max(-m, Math.min(m, a));
}
function updateRange(){
  const p = parseInt(pSel.value,10);
  const m = Math.floor(2*Math.sqrt(p));
  aR.min = -m; aR.max = m;
  aR.value = clampA(parseInt(aR.value,10), p);
}

function render(){
  svg.innerHTML = '';
  const p = parseInt(pSel.value,10);
  updateRange();
  const a = clampA(parseInt(aR.value,10), p);
  aLab.textContent = 'a='+a;
  const sp = Math.sqrt(p);

  const cx = 320, cy = 170, R = 120;
  // disk
  svg.appendChild(SVG('circle',{cx, cy, r:R, fill:'rgba(88,196,221,0.06)', stroke:'var(--blue)', 'stroke-width':1.5, 'stroke-dasharray':'5 3'}));
  // axes
  svg.appendChild(SVG('line',{x1:cx-R-30, y1:cy, x2:cx+R+30, y2:cy, stroke:'var(--line)', 'stroke-width':1}));
  svg.appendChild(SVG('line',{x1:cx, y1:cy-R-30, x2:cx, y2:cy+R+30, stroke:'var(--line)', 'stroke-width':1}));
  svg.appendChild(SVG('text',{x:cx+R+20, y:cy+16, 'font-size':11, fill:'var(--mute)'}))
    .textContent = 'Re';

  // eigenvalues
  const disc = a*a - 4*p;
  let a1, a2;
  if(disc >= 0){
    const s = Math.sqrt(disc);
    a1 = {re:(a+s)/2, im:0};
    a2 = {re:(a-s)/2, im:0};
  } else {
    const s = Math.sqrt(-disc)/2;
    a1 = {re:a/2, im:s};
    a2 = {re:a/2, im:-s};
  }
  // mapping: unit circle of radius sp maps to radius R
  for(const [pt, col] of [[a1,'var(--yellow)'],[a2,'var(--pink)']]){
    const sx = cx + R * pt.re / sp;
    const sy = cy - R * pt.im / sp;
    svg.appendChild(SVG('circle',{cx:sx, cy:sy, r:6, fill:col, stroke:'#0b0f16', 'stroke-width':1.5}));
    // dashed line to origin
    svg.appendChild(SVG('line',{x1:cx, y1:cy, x2:sx, y2:sy, stroke:col, 'stroke-width':1, 'stroke-dasharray':'3 3', opacity:0.5}));
  }

  // label radius
  const rlab = SVG('text',{x:cx+R*0.70, y:cy-R*0.70-6, 'text-anchor':'middle', 'font-size':11, fill:'var(--mute)'});
  rlab.textContent = '|α|=√p='+sp.toFixed(2);
  svg.appendChild(rlab);

  // text box on right
  const tx = 480;
  let ty = 70;
  const add = (s, col='var(--ink)', sz=13) => {
    const t = SVG('text',{x:tx, y:ty, 'font-size':sz, fill:col});
    t.textContent = s; svg.appendChild(t); ty += sz+5;
  };
  add('p = ' + p, 'var(--yellow)', 14);
  add('a_p = ' + a);
  add('disc = a² − 4p = ' + disc);
  add('|α| = |β| = √p = ' + sp.toFixed(3));
  add('α + β = ' + a);
  add('α · β = ' + p);
  if(disc < 0){
    add('eigenvalues: complex conjugate', 'var(--cyan)', 12);
  } else if(disc === 0){
    add('repeated root (supersingular in char p)', 'var(--pink)', 12);
  } else {
    add('real eigenvalues — on circle boundary', 'var(--pink)', 12);
  }

  text.textContent = "The two Frobenius eigenvalues sit on the circle of radius √p in C. They are complex conjugates exactly when disc = a² − 4p < 0, which is the generic case.";
}

