const root = document.getElementById('w-cyclo');
const svg = root.querySelector('svg');
const elSel = root.querySelector('#cy-ell');
const nRng = root.querySelector('#cy-n');
const nLab = root.querySelector('#cy-nlab');
const aIn  = root.querySelector('#cy-a');
const aHint = root.querySelector('#cy-ahint');
const text = root.querySelector('#cy-text');

function gcd(a,b){ while(b){ [a,b]=[b,a%b]; } return a; }

function render(){
  svg.innerHTML = '';
  const ell = parseInt(elSel.value,10);
  const n = parseInt(nRng.value,10);
  nLab.textContent = 'n=' + n;
  const N = Math.pow(ell,n);
  let a = parseInt(aIn.value,10);
  if(!Number.isFinite(a)) a = 1;
  // nearest valid a (coprime to ell)
  if(a % ell === 0){ a = a+1; aIn.value = a; }
  const amod = mod(a, N);
  aHint.textContent = "σ acts by ζ ↦ ζ^" + a + " (must be coprime to " + ell + "; mod " + N + " → " + amod + ")";

  const cx = 360, cy = 150, R = 110;
  // outer title
  const tt = SVG('text',{x:cx, y:28, 'text-anchor':'middle', 'font-size':14, fill:'var(--yellow)'});
  tt.textContent = 'μ_'+N+' : '+N+' points';
  svg.appendChild(tt);

  // circle
  svg.appendChild(SVG('circle',{cx, cy, r:R, fill:'none', stroke:'var(--line)', 'stroke-width':1}));
  // points
  const pts = [];
  for(let k=0;k<N;k++){
    const th = 2*Math.PI*k/N - Math.PI/2;
    pts.push([cx + R*Math.cos(th), cy + R*Math.sin(th)]);
  }
  // action arrows k -> a*k (mod N), draw only 'primitive' images from a generator
  for(let k=1;k<N;k++){
    const j = mod(a*k, N);
    const [x1,y1] = pts[k], [x2,y2] = pts[j];
    if(k === j) continue;
    drawArrow(svg, [x1,y1], [x2,y2], {color:'var(--cyan)', markerId:'cy-arr', width:1, pad1:6, pad2:8, curve:10});
  }
  // points on top
  for(let k=0;k<N;k++){
    const prim = (gcd(k,N)===1);
    const r = prim ? 4.5 : 3;
    svg.appendChild(SVG('circle',{cx:pts[k][0], cy:pts[k][1], r,
      fill: prim ? 'var(--yellow)' : 'var(--mute)', stroke:'#0b0f16', 'stroke-width':1}));
  }
  // center label
  const c1 = SVG('text',{x:cx, y:cy-6, 'text-anchor':'middle', 'font-size':13, fill:'var(--mute)'});
  c1.textContent = 'ζ ↦ ζ^'+amod;
  svg.appendChild(c1);
  const c2 = SVG('text',{x:cx, y:cy+12, 'text-anchor':'middle', 'font-size':12, fill:'var(--mute)'});
  c2.textContent = '(Z/'+N+')^× has φ('+N+')='+phi(N)+' units';
  svg.appendChild(c2);

  const isUnit = (gcd(amod, N) === 1);
  text.textContent = isUnit
    ? "Valid χ(σ) = "+amod+" ∈ (Z/"+N+")^×. On the "+N+"-th roots of unity, σ permutes ζ^k to ζ^("+amod+"·k mod "+N+"). Yellow dots are primitive roots; gray dots are higher-order fixed loci."
    : "NOT a unit: "+amod+" shares a factor with "+N+", so this is not a Galois action on μ_"+N+".";
}

function phi(n){
  let r = n, m = n;
  for(let p=2;p*p<=m;p++){
    if(m%p===0){ while(m%p===0) m/=p; r -= r/p; }
  }
  if(m>1) r -= r/m;
  return Math.round(r);
}

