    'level N = ' + F.N
  ];
  let ry = 110;
  for(const r of rules){
    const t = SVG('text',{x:500, y:ry, 'font-size':13, fill:'var(--ink)', 'font-family':'ui-monospace,monospace'});
    t.textContent = r;
    svg.appendChild(t);
    ry += 24;
  }

  text.textContent = F.note + " Continuity and compatibility across primes ℓ is part of Deligne's construction.";
}

fSel.addEventListener('change', render);
render();
